// idが'myElement'の要素の背景色を赤に設定します。
let element = document.getElementById('myElement');
element.style.backgroundColor = 'red';
// このコードを実行すると、idが'myElement'の要素の背景色が赤に変更されます。

// idが'myElement'の要素の背景色を赤にし、文字色を白に設定します。
let element = document.getElementById('myElement');
element.style.backgroundColor = 'red';
element.style.color = 'white';
// このコードを実行すると、idが'myElement'の要素の背景色が赤に、文字色が白に変更されます。

// idが'myElement'の要素の背景色を取得します。
let element = document.getElementById('myElement');
let backgroundColor = element.style.backgroundColor;
console.log(backgroundColor);
// このコードを実行すると、idが'myElement'の要素の現在の背景色がコンソールに表示されます。

// idが'myElement'の要素の'class'属性値を'newClass'に設定します。
let element = document.getElementById('myElement');
element.setAttribute('class', 'newClass');
// このコードを実行すると、idが'myElement'の要素の'class'属性値が'newClass'に設定されます。

// idが'myElement'の要素の'class'属性値を取得します。
let element = document.getElementById('myElement');
let className = element.getAttribute('class');
console.log(className);
// このコードを実行すると、idが'myElement'の要素の'class'属性値がコンソールに表示されます。

// idが'myElement'の要素の'class'属性を削除します。
let element = document.getElementById('myElement');
element.removeAttribute('class');
// このコードを実行すると、idが'myElement'の要素から'class'属性が削除されます。

// idが'myElement'の要素の'data-custom'属性を設定し、取得します。
let element = document.getElementById('myElement');
element.dataset.custom = 'value';
let customValue = element.dataset.custom;
console.log(customValue);
// このコードを実行すると、idが'myElement'の要素に'data-custom'属性が設定され、その値がコンソールに表示されます。

// idが'myElement'の要素に新しいCSSクラスを追加し、その後削除します。
let element = document.getElementById('myElement');
element.classList.add('newClass');
console.log(element.classList);
element.classList.remove('newClass');
console.log(element.classList);
// このコードを実行すると、idが'myElement'の要素にCSSクラスが追加され、その後削除される過程がコンソールに表示されます。

// idが'myElement'の要素が'checkClass'というCSSクラスを持っているか確認します。
let element = document.getElementById('myElement');
let hasClass = element.classList.contains('checkClass');
console.log(hasClass);
// このコードを実行すると、idが'myElement'の要素が'checkClass'というCSSクラスを持っているかどうかがコンソールに表示されます。

// idが'myElement'の要素の'toggleClass'というCSSクラスを切り替えます。
let element = document.getElementById('myElement');
element.classList.toggle('toggleClass');
console.log(element.classList);
element.classList.toggle('toggleClass');
console.log(element.classList);
// このコードを実行すると、idが'myElement'の要素の'toggleClass'というCSSクラスが切り替えられる過程がコンソールに表示されます。
